#!/usr/bin/env bash
# commercial-dd-cdd.sh — 商业尽调（commercial DD / CDD） SOP walkthrough for 管理咨询.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="管理咨询"
WORKFLOW="商业尽调（commercial DD / CDD）"

usage() {
  cat <<EOF
commercial-dd-cdd.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./commercial-dd-cdd.sh             # interactive
  ./commercial-dd-cdd.sh --dry-run
  ./commercial-dd-cdd.sh --json
  ./commercial-dd-cdd.sh --explain
  ./commercial-dd-cdd.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "商业尽调（commercial DD / CDD）" 工作流。

一句话: PE 投前的快节奏「这笔投资值不值」尽调 —— 经「定投资命题 → 市场吸引力 → 竞争位势 → 客户视角 → 增长可持续性 → 形成 go/no-go view」在极紧时间窗（常 2-6 周）验证标的商业计划是否站得住。是 workflow 1/2 的高压特化版，Bain/L.E.K./精品所的核心业务线。

入门 SOP 共 6 步, 失败模式自检 5 项。

相关心智模型:
  • 假设驱动是地图不是答案：先射箭再画靶 ⇄ 随时 kill 假设（第一性张力）: 面对模糊大问题，资深咨询人不从穷举数据出发，而是 Day-1 就基于经验立一个**可证伪**的初步答案（hypothesis / initial hypothesis）当地图，再只做能 kill 或 
  • 战略 = 做选择 / 做不同，不是运营效率、不是愿望清单: 这行顶级战略 figure 跨流派一致——战略的本质是**逼自己做取舍**（Martin：where-to-play × how-to-win 两个不可分割的选择；Rumelt：kernel = 诊断

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定投资命题 / deal thesis**：与 PE 客户对齐「这笔投资的核心赌注是什么」（市场会增长？标的能扩份额？协同？），把它拆成可验证的关键假设。(evidence: [T03-S012, T03-S013])"
  "**市场吸引力（market attractiveness）**：研究市场规模、增长率、结构性吸引力（常用五力 / 市场细分）。(evidence: [T03-S012])"
  "**竞争位势（competitive position）**：标的 vs 竞品的份额、差异化、可防御性。(evidence: [T03-S012])"
  "**客户视角（customer view）**：通过客户访谈/调研验证需求真实性、留存、转换风险（常重度用专家网络 + 客户 survey）。(evidence: [T03-S012], 交叉 [T02-S009])"
  "**增长可持续性（growth sustainability）**：验证标的商业计划里的增长假设现实吗、可持续吗。(evidence: [T03-S012])"
  "**综合成 go/no-go view + 风险**：把各层综合成对投资命题的整体判断 + 关键风险 + 情景。(evidence: [T03-S012, T04-S041])"
)
declare -a FAILURE_MODES=(
  "**照单全收卖方增长故事**：把标的自画的曲线当真。避免：默认怀疑，找证伪证据。**自检**：「这个增长假设，有没有独立于标的之外的证据支撑？」"
  "**漏掉 primary customer view**：只看二手数据。避免：CDD 必做客户访谈/专家 call。**自检**：「我真的听到目标客户怎么说了吗，还是只看了报告？」"
  "**踩 MNPI 合规红线**：专家 call 套上市公司内幕。避免：明确合规边界、不问不接受 MNPI。**自检**：「这个专家要说的，是公开可得的行业知识，还是某上市公司的内幕？后者立刻打住。」(evidence: [T02-S028])"
  "**均匀铺开、时间窗内做不完**：不优先 deal-breaker。避免：先攻最可能 kill deal 的 2-3 个假设。**自检**：「如果只剩 3 天，哪个假设错了会让 PE 不投？先验证它。」"
  "**AI 生成数据进 CDD 报告没核验**（decay HIGH）：幻觉数字影响投资决策。避免：每个 AI 数字/引用核验到源（Deloitte 殷鉴）。**自检**：「报告里这个关键数字，我对到原始来源了吗？」(evidence: [T03-S009])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "commercial-dd-cdd-walkthrough"
fi
